package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.*;
import org.junit.jupiter.api.Test;
import java.lang.reflect.Field;

class CSVFormatTest {

    @Test
    void testGetAutoFlush_DefaultInstance() {
        // Using DEFAULT constant, which has autoFlush = false
        assertFalse(CSVFormat.DEFAULT.getAutoFlush());
    }

    @Test
    void testGetAutoFlush_CustomInstanceTrue() throws Exception {
        CSVFormat format = createCSVFormatWithAutoFlush(true);
        assertTrue(format.getAutoFlush());
    }

    @Test
    void testGetAutoFlush_CustomInstanceFalse() throws Exception {
        CSVFormat format = createCSVFormatWithAutoFlush(false);
        assertFalse(format.getAutoFlush());
    }

    private CSVFormat createCSVFormatWithAutoFlush(boolean autoFlush) throws Exception {
        // Use reflection to create a CSVFormat instance with specific autoFlush value
        // Find the CSVFormat class constructor with all parameters
        Class<CSVFormat> clazz = CSVFormat.class;
        // Constructor parameters:
        // (char delimiter, Character quoteChar, QuoteMode quoteMode,
        //  Character commentStart, Character escape, boolean ignoreSurroundingSpaces,
        //  boolean ignoreEmptyLines, String recordSeparator, String nullString,
        //  Object[] headerComments, String[] header, boolean skipHeaderRecord,
        //  boolean allowMissingColumnNames, boolean ignoreHeaderCase, boolean trim,
        //  boolean trailingDelimiter, boolean autoFlush)
        var constructor = clazz.getDeclaredConstructor(char.class, Character.class, QuoteMode.class,
                Character.class, Character.class, boolean.class, boolean.class, String.class,
                String.class, Object[].class, String[].class, boolean.class,
                boolean.class, boolean.class, boolean.class, boolean.class, boolean.class);
        constructor.setAccessible(true);

        return constructor.newInstance(',',
                '"',
                null,
                null,
                null,
                false,
                false,
                "\r\n",
                null,
                null,
                null,
                false,
                false,
                false,
                false,
                false,
                autoFlush);
    }
}
